    const result = await payment.processPayment({
      cardNumber: '4532015112830366',
      amount: 100.00,
      currency: 'USD'
    });
    expect(result.success).toBe(true);
    expect(result.transactionId).toBeDefined();
  });

  test('should validate card number with Luhn algorithm', () => {
    expect(payment.validateCard('4532015112830366')).toBe(true);
    expect(payment.validateCard('4532015112830367')).toBe(false);
  });

  test('should reject card with insufficient funds', async () => {
    const result = await payment.processPayment({
      cardNumber: '4532015112830366',
      amount: 99999.00,
      currency: 'USD'
    });
    expect(result.success).toBe(false);
    expect(result.error).toBe('insufficient_funds');
  });

  test('should format currency correctly', () => {
    expect(payment.formatCurrency(100.5)).toBe('$100.50');
  });
});

function validateCard(cardNumber) {
  // Bug: Luhn algorithm not implemented
  return cardNumber.length === 16;
}

async function checkFunds(cardNumber, amount) {
  // Bug: Not implemented - would call payment gateway
  throw new Error('Funds check not implemented');
}

async function processPayment(paymentInfo) {
  const {cardNumber, amount, currency} = paymentInfo;

  // Validate card
  if (!validateCard(cardNumber)) {
    throw new Error('Card validation failed');
  }

  // Check funds
  const hasFunds = await checkFunds(cardNumber, amount);
  if (!hasFunds) {
    return {success: false, error: 'insufficient_funds'};
  }

  // Process payment
  return {
    success: true,
    transactionId: 'txn_' + Date.now()
  };
}

function formatCurrency(amount) {
  return '$' + amount.toFixed(2);
}

